import{_ as l,o as i,c as o,ae as a}from"./chunks/framework.BalxkeZv.js";const h=JSON.parse('{"title":"发布产物","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/release-artifacts.md","filePath":"deploy/release-artifacts.md","lastUpdated":1777140393000}'),c={name:"deploy/release-artifacts.md"};function d(t,e,s,r,u,n){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="发布产物" tabindex="-1">发布产物 <a class="header-anchor" href="#发布产物" aria-label="Permalink to &quot;发布产物&quot;">​</a></h1><h2 id="ci-流水线" tabindex="-1">CI 流水线 <a class="header-anchor" href="#ci-流水线" aria-label="Permalink to &quot;CI 流水线&quot;">​</a></h2><p>仓库使用以下 GitHub Actions 流水线完成三平台构建与发布：</p><ul><li><code>release-ci</code><ul><li>负责质量门禁、三平台构建、桌面打包、Windows 安装后冒烟验证。</li></ul></li><li><code>release-publish</code><ul><li>监听 <code>release-ci</code> 成功结果，将构建产物发布到 GitHub Releases。</li><li><code>main</code> 分支推送产出 <code>pre-release</code>。</li><li><code>v*</code> 标签推送产出正式 release。</li></ul></li></ul><h2 id="产物命名基线" tabindex="-1">产物命名基线 <a class="header-anchor" href="#产物命名基线" aria-label="Permalink to &quot;产物命名基线&quot;">​</a></h2><p>CI artifact 与最终发布资产统一遵循以下命名规则：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{component}-{platform}-{arch-or-target}-{package_kind?}</span></span></code></pre></div><p>说明：</p><ul><li><code>component</code><ul><li><code>subforge-core</code></li><li><code>subforge-desktop</code></li></ul></li><li><code>platform</code><ul><li><code>ubuntu-22.04</code></li><li><code>windows-10</code></li><li><code>macos-13</code></li><li>这里使用稳定的对外发布标签，不直接复用 <code>windows-latest</code> / <code>macos-latest</code> 这类会漂移的 CI runner 名称</li></ul></li><li><code>arch-or-target</code><ul><li>优先使用 Rust target triple，例如 <code>x86_64-unknown-linux-musl</code></li></ul></li><li><code>package_kind</code><ul><li>仅对安装包类产物追加，例如 <code>nsis</code>、<code>dmg</code>、<code>deb</code>、<code>appimage</code></li></ul></li></ul><p>示例：</p><ul><li><code>subforge-core-ubuntu-22.04-x86_64-unknown-linux-musl</code></li><li><code>subforge-core-windows-10-x86_64-pc-windows-msvc</code></li><li><code>subforge-desktop-macos-13-aarch64-apple-darwin-dmg</code></li><li><code>subforge-desktop-ubuntu-22.04-x86_64-unknown-linux-gnu-appimage</code></li></ul><h2 id="保留策略" tabindex="-1">保留策略 <a class="header-anchor" href="#保留策略" aria-label="Permalink to &quot;保留策略&quot;">​</a></h2><ul><li>CI artifact 默认保留 <code>14</code> 天，用于回归排查与安装包追溯。</li><li><code>release-publish</code> 会将 <code>subforge-*</code> 前缀产物同步到 GitHub Releases。</li><li>仅用于流水线诊断的日志工件不会进入正式发布资产列表。</li></ul><h2 id="当前覆盖范围" tabindex="-1">当前覆盖范围 <a class="header-anchor" href="#当前覆盖范围" aria-label="Permalink to &quot;当前覆盖范围&quot;">​</a></h2><ul><li>Core 独立二进制 <ul><li>Linux GNU</li><li>Linux musl</li><li>Windows x64</li><li>macOS x64 / arm64</li></ul></li><li>Desktop 构建产物 <ul><li>Windows x64</li><li>macOS x64 / arm64</li><li>Linux x64</li></ul></li><li>Desktop 安装包 <ul><li>Windows <code>NSIS</code></li><li>macOS <code>DMG</code></li><li>Linux <code>DEB</code> / <code>AppImage</code></li></ul></li></ul>',15)])])}const m=l(c,[["render",d]]);export{h as __pageData,m as default};
